import type * as React from 'react';

import {cn} from '@/lib/utils';

import {Label as LabelPrimitive} from 'radix-ui';

/**
 * Renders an accessible label associated with controls.
 *
 * ### Component Props
 *
 * See [Label props](https://www.radix-ui.com/primitives/docs/components/label) documentation for full details.
 *
 * | Prop      | Type      | Default |
 * | :-------- | :-------- | :------ |
 * | _asChild_ | `boolean` | `false` |
 * | _htmlFor_ | `string`  | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Label htmlFor="email">Email</Label>
 * <Input id="email" type="email" />
 * ```
 */
function Label({
  className,
  ...props
}: React.ComponentProps<typeof LabelPrimitive.Root>) {
  return (
    <LabelPrimitive.Root
      data-slot="label"
      className={cn(
        'flex items-center gap-2 text-label leading-label font-label tracking-label select-none group-data-[disabled=true]:pointer-events-none group-data-[disabled=true]:opacity-50 peer-disabled:cursor-not-allowed peer-disabled:opacity-50',
        className
      )}
      {...props}
    />
  );
}

export {Label};
